    s = s.replace(' ', '')

    def div_toward_zero(a, b):
        return (abs(a) // abs(b)) * (1 if a * b >= 0 else -1)

    def ap(st, sg, nm):
        if sg == '+':
            st.append(nm)
        elif sg == '-':
            st.append(-nm)
        elif sg == '*':
            st.append(st.pop() * nm)
        elif sg == '/':
            st.append(div_toward_zero(st.pop(), nm))

    def h(i):
        st = []
        nm = 0
        sg = '+'
