            c = s[i]
            if c.isdigit():
                nm = nm * 10 + int(c)
                i += 1
            elif c == '(':
                nm, i = h(i + 1)
            else:
                ap(st, sg, nm)
                nm = 0
                if c == ')':
                    return sum(st), i + 1
                sg = c
                i += 1
        ap(st, sg, nm)
        return sum(st), i

    return h(0)[0]
